// Package gastown — Poller invokes the gt CLI to collect rig, polecat, and
// convoy state, enriches it with session data, and maps it to the standardised
// orchestrator.State model.
package gastown

import (
	"context"
	"encoding/json"
	"os/exec"
	"path/filepath"
	"sort"
	"sync"
	"time"

	"irrlicht/core/domain/orchestrator"
	"irrlicht/core/domain/session"
)

// SessionLister provides read access to active sessions for CWD matching.
type SessionLister interface {
	ListAll() ([]*session.SessionState, error)
}

// Poller queries the gt CLI for rig, polecat, and convoy state and maps
// the results to the standardised orchestrator.State model.
type Poller struct {
	collector *Collector
	gtBin     string
	interval  time.Duration
	sessions  SessionLister
}

// NewPoller creates a Poller that reads from the given collector and
// shells out to gtBin for rig/polecat state.
func NewPoller(collector *Collector, gtBin string, interval time.Duration, sessions SessionLister) *Poller {
	return &Poller{
		collector: collector,
		gtBin:     gtBin,
		interval:  interval,
		sessions:  sessions,
	}
}

// BuildOrchestratorState fetches current gt state and returns the standardised
// orchestrator.State model. Called by Adapter on each poll tick.
func (p *Poller) BuildOrchestratorState(ctx context.Context) *orchestrator.State {
	daemon := p.collector.DaemonState()
	now := time.Now().UTC()
	gtRoot := p.collector.Root()

	if !p.collector.Detected() || p.gtBin == "" {
		return &orchestrator.State{
			Adapter:   "gastown",
			Running:   false,
			Root:      gtRoot,
			UpdatedAt: now,
		}
	}

	// Fetch rig list, polecat list, and convoy list in parallel.
	var wg sync.WaitGroup
	var rigs []RigState
	var polecats []PolecatState
	var convoys []ConvoyState

	wg.Add(3)
	go func() { defer wg.Done(); rigs = p.fetchRigs(ctx) }()
	go func() { defer wg.Done(); polecats = p.fetchPolecats(ctx) }()
	go func() { defer wg.Done(); convoys = p.fetchConvoys(ctx) }()
	wg.Wait()

	running := daemon != nil && daemon.Running
	return p.mapToOrchestratorState(rigs, polecats, convoys, running, now)
}

// mapToOrchestratorState maps raw Gas Town types to the standardised model.
func (p *Poller) mapToOrchestratorState(
	rigs []RigState,
	polecats []PolecatState,
	convoys []ConvoyState,
	running bool,
	now time.Time,
) *orchestrator.State {
	gtRoot := p.collector.Root()

	state := &orchestrator.State{
		Adapter:   "gastown",
		Running:   running,
		Root:      gtRoot,
		UpdatedAt: now,
	}

	// Get all sessions for CWD matching.
	var sessions []*session.SessionState
	if p.sessions != nil {
		sessions, _ = p.sessions.ListAll()
	}

	// Build session index: CWD → session for fast lookup.
	type sessionInfo struct {
		sessionID string
		state     string
	}
	cwdToSession := make(map[string]sessionInfo)
	for _, s := range sessions {
		if s.CWD == "" {
			continue
		}
		cwdToSession[filepath.Clean(s.CWD)] = sessionInfo{
			sessionID: s.SessionID,
			state:     s.State,
		}
	}

	// matchSession checks if any session has a CWD under the given path.
	matchSession := func(basePath string) (string, string) {
		basePath = filepath.Clean(basePath)
		for cwd, info := range cwdToSession {
			rel, err := filepath.Rel(basePath, cwd)
			if err != nil {
				continue
			}
			if len(rel) > 0 && rel[0] != '.' {
				return info.sessionID, info.state
			}
			if rel == "." {
				return info.sessionID, info.state
			}
		}
		return "", ""
	}

	// Global agents (mayor, deacon).
	globalAgents := []orchestrator.GlobalAgent{}
	mayorMeta := roleMeta[RoleMayor]
	if mayorSID, mayorState := matchSession(filepath.Join(gtRoot, "mayor")); mayorSID != "" {
		globalAgents = append(globalAgents, orchestrator.GlobalAgent{
			Role:        RoleMayor,
			Icon:        mayorMeta.Icon,
			Description: mayorMeta.Desc,
			SessionID:   mayorSID,
			State:       mayorState,
		})
	} else {
		globalAgents = append(globalAgents, orchestrator.GlobalAgent{
			Role:        RoleMayor,
			Icon:        mayorMeta.Icon,
			Description: mayorMeta.Desc,
			State:       "idle",
		})
	}
	deaconMeta := roleMeta[RoleDeacon]
	if deaconSID, deaconState := matchSession(filepath.Join(gtRoot, "deacon")); deaconSID != "" {
		globalAgents = append(globalAgents, orchestrator.GlobalAgent{
			Role:        RoleDeacon,
			Icon:        deaconMeta.Icon,
			Description: deaconMeta.Desc,
			SessionID:   deaconSID,
			State:       deaconState,
		})
	} else {
		globalAgents = append(globalAgents, orchestrator.GlobalAgent{
			Role:        RoleDeacon,
			Icon:        deaconMeta.Icon,
			Description: deaconMeta.Desc,
			State:       "idle",
		})
	}
	state.GlobalAgents = globalAgents

	// Group polecats by rig.
	polecatsByRig := make(map[string][]PolecatState)
	for _, pc := range polecats {
		polecatsByRig[pc.Rig] = append(polecatsByRig[pc.Rig], pc)
	}

	// Build codebases from rigs.
	codebases := make([]orchestrator.Codebase, 0, len(rigs))
	for _, rig := range rigs {
		cb := orchestrator.Codebase{
			Name:   rig.Name,
			Status: rig.Status,
		}

		// Main worktree: witness + refinery + crew workers.
		mainWorktree := orchestrator.Worktree{
			Path:   filepath.Join(gtRoot, rig.Name),
			IsMain: true,
		}

		mainWorkers := []orchestrator.Worker{}

		// Witness worker.
		witnessMeta := roleMeta[RoleWitness]
		witnessWorker := orchestrator.Worker{
			Role:        RoleWitness,
			Icon:        witnessMeta.Icon,
			Description: witnessMeta.Desc,
			State:       rig.Witness,
		}
		if sid, sState := matchSession(filepath.Join(gtRoot, rig.Name, "witness")); sid != "" {
			witnessWorker.SessionID = sid
			witnessWorker.State = sState
		}
		mainWorkers = append(mainWorkers, witnessWorker)

		// Refinery worker.
		refineryMeta := roleMeta[RoleRefinery]
		refineryWorker := orchestrator.Worker{
			Role:        RoleRefinery,
			Icon:        refineryMeta.Icon,
			Description: refineryMeta.Desc,
			State:       rig.Refinery,
		}
		if sid, sState := matchSession(filepath.Join(gtRoot, rig.Name, "refinery")); sid != "" {
			refineryWorker.SessionID = sid
			refineryWorker.State = sState
		}
		mainWorkers = append(mainWorkers, refineryWorker)

		// Crew workers.
		crewMeta := roleMeta[RoleCrew]
		for _, s := range sessions {
			if s.CWD == "" {
				continue
			}
			ri := DeriveRole(s.CWD, gtRoot)
			if ri == nil || ri.Role != RoleCrew || ri.Rig != rig.Name {
				continue
			}
			mainWorkers = append(mainWorkers, orchestrator.Worker{
				Role:        RoleCrew,
				Icon:        crewMeta.Icon,
				Description: crewMeta.Desc,
				Name:        ri.Name,
				SessionID:   s.SessionID,
				State:       s.State,
			})
		}

	}

	orchMonitor := services.NewOrchestratorMonitor(orchWatchers, push, logger)
	{
		orchCtx, orchCancel := context.WithCancel(context.Background())
		defer orchCancel()
		// Start each orchestrator watcher.
		for _, ow := range orchWatchers {
			go func() {
				if err := ow.Watch(orchCtx); err != nil && err != context.Canceled {
					logger.LogError("orchestrator-watcher", "", fmt.Sprintf("watcher error: %v", err))
				}
			}()
		}
		go func() {
			if err := orchMonitor.Run(orchCtx); err != nil && err != context.Canceled {
				logger.LogError("orchestrator-monitor", "", fmt.Sprintf("monitor error: %v", err))
			}
		}()
	}

	// Register API endpoints (after orchMonitor is available).
	mux.HandleFunc("GET /api/v1/sessions", handleGetSessions(cachedRepo, orchMonitor))
	mux.HandleFunc("GET /api/v1/orchestrators/{name}", handleGetOrchestrator(orchMonitor))
	mux.HandleFunc("GET /api/v1/gastown", handleGetOrchestrator(orchMonitor)) // backward compat

	// Inbound adapters: watch agent transcript directories for session files.
	claudeCodeWatcher := claudecode.New(cfg.MaxSessionAge)
	codexWatcher := codex.New(cfg.MaxSessionAge)
	piWatcher := pi.New(cfg.MaxSessionAge)

	// Process scanner: detects Claude Code processes before they create a
	// transcript, so the session appears as ready from the moment the app opens.
	procScanner := processlifecycle.NewScanner(
		"claude",
		claudecode.AdapterName,
		claudeCodeWatcher.Root(),
		0, // use default interval
	)
	// Suppress ghost proc sessions for directories that already have a real
	// (transcript-backed) session, even if the transcript hasn't been written
	// recently. Without this, idle sessions allow short-lived helper processes
	// to create spurious proc-<pid> entries in the UI.
	procScanner.WithSessionChecker(func(projectDir string) bool {
		sessions, err := cachedRepo.ListAll()
		if err != nil {
			return false
		}
		for _, s := range sessions {
			if strings.HasPrefix(s.SessionID, "proc-") {
				continue
			}
			if s.TranscriptPath != "" &&
				filepath.Base(filepath.Dir(s.TranscriptPath)) == projectDir {
				return true
			}
		}
		return false
	})

	watchers := []inbound.AgentWatcher{claudeCodeWatcher, codexWatcher, piWatcher, procScanner}

	// Per-adapter PID discovery: Claude Code uses CWD-based matching,
	// Codex/Pi use transcript file writer detection.
	pidDiscovers := map[string]services.PIDDiscoverFunc{
		claudecode.AdapterName: claudecode.DiscoverPID,
		codex.AdapterName:      codex.DiscoverPID,
		pi.AdapterName:         pi.DiscoverPID,
	}

	// SessionDetector: orchestrates AgentWatchers + ProcessWatcher.
	detector = services.NewSessionDetector(
		watchers, pwPort,
		cachedRepo, logger, gitResolver, metricsCollector, push,
		Version, cfg.ReadySessionTTL,
		pidDiscovers,
	)
	detector.SetAdapterPolicies(map[string]domainagent.StatePolicy{
		claudecode.AdapterName: claudecode.StatePolicy(),
		codex.AdapterName:      codex.StatePolicy(),
		pi.AdapterName:         pi.StatePolicy(),
	})
	{
		detectorCtx, detectorCancel := context.WithCancel(context.Background())
		defer detectorCancel()
		logger.LogInfo("startup", "", fmt.Sprintf("watching Claude Code (%s), Codex (%s), Pi (%s)",
			claudeCodeWatcher.Root(), codexWatcher.Root(), piWatcher.Root()))
		for _, w := range watchers {
			go func() {
				if err := w.Watch(detectorCtx); err != nil && err != context.Canceled {
					logger.LogError("agent-watcher", "", fmt.Sprintf("watcher error: %v", err))
				}
			}()
		}
		go func() {
			if err := detector.Run(detectorCtx); err != nil && err != context.Canceled {
				logger.LogError("session-detector", "", fmt.Sprintf("detector error: %v", err))
			}
		}()
	}

	logger.LogInfo("startup", "", fmt.Sprintf("irrlichd %s listening on unix:%s and tcp:%s", Version, sockPath, tcpAddr))

	// Wait for SIGTERM or SIGINT.
	sig := make(chan os.Signal, 1)
	signal.Notify(sig, syscall.SIGTERM, syscall.SIGINT)
	<-sig

	logger.LogInfo("shutdown", "", "signal received, shutting down")

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if mdnsAdv != nil {
		mdnsAdv.Shutdown(ctx)
	}

	if err := srv.Shutdown(ctx); err != nil {
		logger.LogError("shutdown", "", fmt.Sprintf("graceful shutdown error: %v", err))
	}
}

// socketPath returns the Unix socket path for irrlichd.
func socketPath() string {
	home, err := os.UserHomeDir()
	if err != nil {
		return "/tmp/irrlichd.sock"
	}
	return filepath.Join(home, ".local", "share", "irrlicht", "irrlichd.sock")
}

func handleGetSessions(repo outbound.SessionRepository, orchMonitor *services.OrchestratorMonitor) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		sessions, err := repo.ListAll()
		if err != nil {
			http.Error(w, "internal error", http.StatusInternalServerError)
			return
		}
		w.Header().Set("Content-Type", "application/json")
		resp := session.BuildDashboard(sessions, orchMonitor.State("gastown"))
		json.NewEncoder(w).Encode(resp)
	}
}

func handleGetOrchestrator(monitor *services.OrchestratorMonitor) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")

		// Determine which orchestrator: from path param or default to "gastown".
		name := r.PathValue("name")
		if name == "" {
			name = "gastown"
		}

		state := monitor.State(name)
		if state == nil {
			json.NewEncoder(w).Encode(struct {
				Detected bool `json:"detected"`
			}{Detected: false})
			return
		}

		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		enc.Encode(state)
	}
}

func handleGetState(repo outbound.SessionRepository) http.HandlerFunc {
	type sessionEntry struct {
		ID                 string  `json:"id"`
		ProjectName        string  `json:"projectName,omitempty"`
		State              string  `json:"state"`
		Model              string  `json:"model,omitempty"`
		ContextUtilization float64 `json:"contextUtilization"`
		TotalTokens        int64   `json:"totalTokens"`
	}

	type stateResponse struct {
		Sessions     []sessionEntry `json:"sessions"`
		SessionCount int            `json:"sessionCount"`
		WorkingCount int            `json:"workingCount"`
		WaitingCount int            `json:"waitingCount"`
		ReadyCount   int            `json:"readyCount"`
		LastUpdated  string         `json:"lastUpdated"`
	}

	return func(w http.ResponseWriter, r *http.Request) {
		sessions, err := repo.ListAll()
		if err != nil {
			http.Error(w, "internal error", http.StatusInternalServerError)
			return
		}

		entries := make([]sessionEntry, 0, len(sessions))
		var workingCount, waitingCount, readyCount int
		for _, s := range sessions {
			var ctxUtil float64
			var totalTokens int64
			if s.Metrics != nil {
				ctxUtil = s.Metrics.ContextUtilization
				totalTokens = s.Metrics.TotalTokens
			}
			model := s.Model
			if s.Metrics != nil && s.Metrics.ModelName != "" && s.Metrics.ModelName != "unknown" {
				model = s.Metrics.ModelName
			}
			entries = append(entries, sessionEntry{
				ID:                 s.SessionID,
				ProjectName:        s.ProjectName,
				State:              s.State,
				Model:              model,
				ContextUtilization: ctxUtil,
				TotalTokens:        totalTokens,
			})
			switch s.State {
			case session.StateWorking:
				workingCount++
			case session.StateWaiting:
				waitingCount++
			case session.StateReady:
				readyCount++
			}
		}

		resp := stateResponse{
			Sessions:     entries,
			SessionCount: len(sessions),
			WorkingCount: workingCount,
			WaitingCount: waitingCount,
			ReadyCount:   readyCount,
			LastUpdated:  time.Now().UTC().Format(time.RFC3339),
		}

		w.Header().Set("Content-Type", "application/json")
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		enc.Encode(resp)
	}
}

// localhostOnly wraps an HTTP handler to reject requests not originating from
// localhost or Unix sockets. Used to protect sensitive endpoints like pprof.
func localhostOnly(h http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		host, _, err := net.SplitHostPort(r.RemoteAddr)
		if err != nil {
			// Unix socket connections have no host:port — allow them.
			h(w, r)
			return
		}
		ip := net.ParseIP(host)
		if ip != nil && ip.IsLoopback() {
			h(w, r)
			return
		}
		http.Error(w, "forbidden", http.StatusForbidden)
	}
}

