        healthTask = Task { [weak self] in
            guard let self else { return }
            if await self.isDaemonReachable() {
                self.daemonRunning = true
                self.logger.info("External daemon already reachable — skipping spawn")
                return
            }
            self.killStaleDaemons()
            self.spawnDaemon()
        }
