19	var upgrader = websocket.Upgrader{
20		CheckOrigin: func(r *http.Request) bool { return true },
21	}
22	
23	// Hub manages WebSocket connections and fans out session state updates.
24	type Hub struct {
25		push outbound.PushBroadcaster
26	}
27	
28	// NewHub creates a Hub backed by the provided PushBroadcaster.
29	func NewHub(push outbound.PushBroadcaster) *Hub {
30		return &Hub{push: push}
31	}
32	
33	// ServeWS upgrades the HTTP connection to WebSocket and streams typed session
34	// state update messages until the client disconnects.
35	// Register on GET /api/v1/sessions/stream.
36	func (h *Hub) ServeWS(w http.ResponseWriter, r *http.Request) {
37		conn, err := upgrader.Upgrade(w, r, nil)
38		if err != nil {
39			return
40		}
41		defer conn.Close()
42	
43		ch := h.push.Subscribe()
44		defer h.push.Unsubscribe(ch)
45	
46		// Set initial read deadline; reset on each pong.
47		conn.SetReadDeadline(time.Now().Add(pongTimeout))
48		conn.SetPongHandler(func(string) error {
49			conn.SetReadDeadline(time.Now().Add(pongTimeout))
50			return nil
51		})
52	
53		// Detect client disconnect via a read pump running concurrently.
54		done := make(chan struct{})
55		go func() {
56			defer close(done)
57			for {
58				if _, _, err := conn.ReadMessage(); err != nil {
59					return
60				}
61			}
62		}()
63	
64		// Ping ticker to keep the connection alive.
65		ticker := time.NewTicker(pingInterval)
66		defer ticker.Stop()
67	
68		for {
69			select {
70			case msg, ok := <-ch:
71				if !ok {
72					return
73				}
74				data, err := json.Marshal(msg)
75				if err != nil {
76					continue
77				}
78				conn.SetWriteDeadline(time.Now().Add(writeTimeout))
79				if err := conn.WriteMessage(websocket.TextMessage, data); err != nil {
80					return
81				}
82			case <-ticker.C:
83				conn.SetWriteDeadline(time.Now().Add(writeTimeout))
84				if err := conn.WriteMessage(websocket.PingMessage, nil); err != nil {
85					return
86				}
87			case <-done:
88				return
89			}
90		}
91	}

