 15	
 16	// SessionRepository implements ports/outbound.SessionRepository using the local filesystem.
 17	type SessionRepository struct {
 18		instancesDir string
 19	}
 20	
 21	// New returns a SessionRepository rooted at the user's Application Support directory.
 22	func New() (*SessionRepository, error) {
 23		homeDir, err := os.UserHomeDir()
 24		if err != nil {
 25			return nil, fmt.Errorf("cannot determine home directory: %w", err)
 26		}
 27		return &SessionRepository{
 28			instancesDir: filepath.Join(homeDir, appSupportDir, "instances"),
 29		}, nil
 30	}
 31	
 32	// NewWithDir returns a SessionRepository rooted at the given directory (useful for tests).
 33	func NewWithDir(dir string) *SessionRepository {
 34		return &SessionRepository{instancesDir: dir}
 35	}
 36	
 37	// InstancesDir returns the directory where session files are stored.
 38	func (r *SessionRepository) InstancesDir() string {
 39		return r.instancesDir
 40	}
 41	
 42	// Load reads a session state from disk. Returns (nil, err) if the file does not exist.
 43	func (r *SessionRepository) Load(sessionID string) (*session.SessionState, error) {
 44		data, err := os.ReadFile(r.statePath(sessionID))
 45		if err != nil {
 46			return nil, err
 47		}
 48		var state session.SessionState
 49		if err := json.Unmarshal(data, &state); err != nil {
 50			return nil, err
 51		}
 52		return &state, nil
 53	}
 54	
 55	// Save atomically writes a session state to disk.
 56	func (r *SessionRepository) Save(state *session.SessionState) error {
 57		if err := os.MkdirAll(r.instancesDir, 0755); err != nil {
 58			return fmt.Errorf("failed to create instances directory: %w", err)
 59		}
 60		data, err := json.MarshalIndent(state, "", "  ")
 61		if err != nil {
 62			return fmt.Errorf("failed to marshal session state: %w", err)
 63		}
 64		path := r.statePath(state.SessionID)
 65		tmpPath := fmt.Sprintf("%s.tmp.%d.%d", path, os.Getpid(), time.Now().UnixNano())
 66		if err := os.WriteFile(tmpPath, data, 0644); err != nil {
 67			return fmt.Errorf("failed to write temp file: %w", err)
 68		}
 69		if err := os.Rename(tmpPath, path); err != nil {
 70			os.Remove(tmpPath)
 71			return fmt.Errorf("failed to rename temp file: %w", err)
 72		}
 73		return nil
 74	}
 75	
 76	// Delete removes a session state file. Returns nil if the file does not exist.
 77	func (r *SessionRepository) Delete(sessionID string) error {
 78		err := os.Remove(r.statePath(sessionID))
 79		if err != nil && os.IsNotExist(err) {
 80			return nil
 81		}
 82		return err
 83	}
 84	
 85	// ListAll returns all session states found in the instances directory.
 86	// Files that cannot be parsed are silently skipped.
 87	func (r *SessionRepository) ListAll() ([]*session.SessionState, error) {
 88		entries, err := os.ReadDir(r.instancesDir)
 89		if err != nil {
 90			if os.IsNotExist(err) {
 91				return nil, nil
 92			}
 93			return nil, err
 94		}
 95		var states []*session.SessionState
 96		for _, entry := range entries {
 97			if entry.IsDir() {
 98				continue
 99			}
100			name := entry.Name()
101			if filepath.Ext(name) != ".json" || strings.Contains(name, ".tmp.") {
102				continue
103			}
104			data, err := os.ReadFile(filepath.Join(r.instancesDir, name))
105			if err != nil {
106				continue
107			}
108			var state session.SessionState
109			if err := json.Unmarshal(data, &state); err != nil {
110				continue
111			}
112			validStates := map[string]bool{
113				session.StateWorking: true,
114				session.StateWaiting: true,
115				session.StateReady:   true,
116			}
117			if !validStates[state.State] {
118				os.Remove(filepath.Join(r.instancesDir, name))
119				continue
120			}
121			states = append(states, &state)
122		}
123		return states, nil
124	}
125	
126	// PruneStale deletes session files older than maxAge and returns the count.
127	// A zero or negative maxAge disables pruning (returns 0, nil).
128	func (r *SessionRepository) PruneStale(maxAge time.Duration) (int, error) {
129		if maxAge <= 0 {
130			return 0, nil
131		}
132		states, err := r.ListAll()
133		if err != nil {
134			return 0, err
135		}
136		pruned := 0
137		for _, s := range states {
138			if s.IsStale(maxAge) {
139				_ = r.Delete(s.SessionID)
140				pruned++
141			}
142		}
143		return pruned, nil
144	}
145	
146	func (r *SessionRepository) statePath(sessionID string) string {
147		return filepath.Join(r.instancesDir, sessionID+".json")
148	}

